	/// <summary>
	/// Prefixes for numbered managed property ranges.
	/// Examples: RefinableString00-199, RefinableInt00-49, Int00-49, Date00-09, etc.
	/// </summary>
	private static readonly string[] NumberedPrefixes = new[]
	{
		"Date",
		"Decimal",
		"Double",
		"Int",
		"RefinableDate",
		"RefinableDateInvariant",
		"RefinableDateSingle",
		"RefinableDecimal",
		"RefinableDouble",
		"RefinableInt",
		"RefinableString",
		"Text",
		"UsageEvent",
		"ViewsLast",
		"ViewsLastMonths",
		"WordCustomRefiner",
		"WordPartCustomRefiner",
	};

	/// <summary>
	/// Checks if the given property name is a known SharePoint managed property.
	/// Returns true for all documented default managed properties and numbered ranges.
	/// Note: Returns false for custom properties, aliases, and autogenerated properties
	/// that are not in the default set.
	/// </summary>
	public static bool IsKnown(string propertyName)
	{
		if (string.IsNullOrEmpty(propertyName))
			return false;

		if (NamedProperties.Contains(propertyName))
			return true;

		// Check numbered patterns (e.g., RefinableString00, Int49, ViewsLast7DaysUniqueUsers)
		foreach (var prefix in NumberedPrefixes)
		{
			if (propertyName.StartsWith(prefix, StringComparison.OrdinalIgnoreCase) &&
				propertyName.Length > prefix.Length)
			{
				var suffix = propertyName.Substring(prefix.Length);
				// Allow pure numbers (e.g., RefinableString00, Int49)
				if (int.TryParse(suffix, out _))
					return true;
				// Allow numbered suffixes with text (e.g., ViewsLast7Days, ViewsLast7DaysUniqueUsers,
				// UsageEvent10LifeTime, UsageEvent10Recent, ViewsLastMonths1Unique)
				if (suffix.Length > 0 && char.IsDigit(suffix[0]))
					return true;
			}
		}

		return false;
	}
